onChange.script:
def _g(obj, key):
	try:
		return obj[key]
	except Exception:
		return None
header = currentValue.value if currentValue is not None else None
hdrId = _g(header, 'Id') if header is not None else None
BlueRidge.Common.Util.log('selectedHeader.onChange hdrId=%s' % hdrId)
if not hdrId or hdrId <= 0:
	if self.view.custom.mode == 'draft':
		self.view.custom.draftId = 0
		self.view.custom.state = {'editDraft': {'Id': 0, 'Name': '', 'EffectiveFrom': '', 'steps': []}, 'selected': {'Id': 0, 'Name': '', 'EffectiveFrom': '', 'steps': []}}
		self.view.custom.mode = 'view'
		self.view.rootContainer.broadcastDirty(False)
	return
publishedAt = _g(header, 'PublishedAt')
deprecatedAt = _g(header, 'DeprecatedAt')
isDraft = (publishedAt is None) and (deprecatedAt is None)
BlueRidge.Common.Util.log('selectedHeader.onChange isDraft=%s publishedAt=%s deprecatedAt=%s' % (isDraft, publishedAt, deprecatedAt))
if isDraft:
	if self.view.custom.draftId == hdrId:
		return
	name = _g(header, 'Name') or ''
	effRaw = _g(header, 'EffectiveFrom')
	effStr = str(effRaw or '')[:10]
	steps = BlueRidge.Parts.RouteTemplate.getSteps(hdrId) or []
	stepsCopy = [dict(s) for s in steps]
	self.view.custom.draftId = hdrId
	self.view.custom.state = {'editDraft': {'Id': hdrId, 'Name': name, 'EffectiveFrom': effStr, 'steps': stepsCopy}, 'selected': {'Id': hdrId, 'Name': name, 'EffectiveFrom': effStr, 'steps': [dict(s) for s in steps]}}
	self.view.custom.mode = 'draft'
	self.view.rootContainer.broadcastDirty(False)
else:
	if self.view.custom.mode == 'draft':
		self.view.custom.draftId = 0
		self.view.custom.state = {'editDraft': {'Id': 0, 'Name': '', 'EffectiveFrom': '', 'steps': []}, 'selected': {'Id': 0, 'Name': '', 'EffectiveFrom': '', 'steps': []}}
		self.view.custom.mode = 'view'
		self.view.rootContainer.broadcastDirty(False)

transforms.code:
out = []
for r in (value or []):
	r = r or {}
	out.append({'seq': r.get('SequenceNumber'), 'areaName': r.get('OperationAreaName') or '', 'opCode': r.get('OperationCode') or '', 'opName': r.get('OperationName') or '', 'isRequired': bool(r.get('IsRequired')), 'dataFields': r.get('DataCollectionSummary') or ''})
return out

onChange.script:
def _g(obj, key):
	try:
		return obj[key]
	except Exception:
		return None
if self.view.custom.selectedVersionId and self.view.custom.selectedVersionId > 0:
	return
curr = currentValue.value if currentValue is not None else None
BlueRidge.Common.Util.log('versions.onChange count=%s' % (len(curr) if curr is not None else 'None'))
if curr is None:
	self.view.custom.selectedVersionId = 0
	return
active = None
for v in curr:
	pub = _g(v, 'PublishedAt')
	dep = _g(v, 'DeprecatedAt')
	if pub and not dep:
		active = v
		break
if active is not None:
	self.view.custom.selectedVersionId = _g(active, 'Id') or 0
elif len(curr) > 0:
	self.view.custom.selectedVersionId = _g(curr[0], 'Id') or 0
else:
	self.view.custom.selectedVersionId = 0

transforms.code:
out = []
for v in (value or []):
	vnum = v.get('VersionNumber', 0)
	name = v.get('Name') or ''
	if v.get('DeprecatedAt'):
		state = 'Deprecated'
	elif v.get('PublishedAt'):
		state = 'Published'
	else:
		state = 'Draft'
	label = 'v' + str(vnum) + ' -- ' + name + ' (' + state + ')'
	out.append({'label': label, 'value': v.get('Id')})
return out

out = []
for r in (value or []):
	r = r or {}
	out.append({'seq': r.get('SequenceNumber'), 'areaName': r.get('OperationAreaName') or '', 'opCode': r.get('OperationCode') or '', 'opName': r.get('OperationName') or '', 'isRequired': bool(r.get('IsRequired')), 'dataFields': r.get('DataCollectionSummary') or ''})
return out

steps = value or []
areas = self.view.custom.areas or []
opCache = self.view.custom.opTemplatesByArea or {}
out = []
total = len(steps)
for i, s in enumerate(steps):
	s = s or {}
	out.append({'rowIndex': i, 'step': dict(s), 'areas': areas, 'opTemplatesByArea': opCache, 'isFirst': (i == 0), 'isLast': (i == total - 1)})
return out

config.script:
def _g(obj, key):
	try:
		return obj[key]
	except Exception:
		return None
action = _g(payload, 'action') if payload is not None else None
BlueRidge.Common.Util.log('routeConfirmDiscard action=%s draftId=%s' % (action, self.view.custom.draftId))
if action != 'confirm':
	return
draftId = self.view.custom.draftId
if not draftId or draftId <= 0:
	BlueRidge.Common.Notify.toast('Discard', 'No draft to discard.', 'warn', 5)
	return
result = BlueRidge.Parts.RouteTemplate.discardDraft(draftId)
BlueRidge.Common.Ui.notifyResult(result, 'Discard', 'Draft discarded.', 'Discard failed')
if not result or not result.get('Status'):
	return
self.view.custom.draftId = 0
self.view.custom.state = {'editDraft': {'Id': 0, 'Name': '', 'EffectiveFrom': '', 'steps': []}, 'selected': {'Id': 0, 'Name': '', 'EffectiveFrom': '', 'steps': []}}
self.view.custom.mode = 'view'
self.view.custom.selectedVersionId = 0
self.rootContainer.reloadVersions()
self.rootContainer.broadcastDirty(False)

def _g(obj, key):
	try:
		return obj[key]
	except Exception:
		return None
if payload is None or _g(payload, 'section') != 'routes':
	return
if self.view.custom.mode != 'draft':
	return
draft = self.view.custom.state.editDraft
name = _g(draft, 'Name')
eff = _g(draft, 'EffectiveFrom')
rawSteps = _g(draft, 'steps') or []
steps = list(rawSteps)
result = BlueRidge.Parts.RouteTemplate.saveAll(self.view.custom.draftId, name, eff, steps)
BlueRidge.Common.Ui.notifyResult(result, 'Route saved', 'Route saved.', 'Save failed')
if not result or not result.get('Status'):
	return
self.view.custom.state.selected = {'Id': _g(draft, 'Id'), 'Name': name, 'EffectiveFrom': eff, 'steps': [dict(s) for s in steps]}
self.rootContainer.reloadVersions()
self.rootContainer.broadcastDirty(False)

def _g(obj, key):
	try:
		return obj[key]
	except Exception:
		return None
if payload is None or _g(payload, 'section') != 'routes':
	return
if self.view.custom.mode != 'draft':
	return
sel = self.view.custom.state.selected
rawSteps = _g(sel, 'steps') or []
self.view.custom.state.editDraft = {'Id': _g(sel, 'Id'), 'Name': _g(sel, 'Name'), 'EffectiveFrom': _g(sel, 'EffectiveFrom'), 'steps': [dict(s) for s in list(rawSteps)]}
self.rootContainer.broadcastDirty(False)

def _g(obj, key):
	try:
		return obj[key]
	except Exception:
		return None
if payload is None:
	return
idx = _g(payload, 'rowIndex')
newStep = _g(payload, 'step')
BlueRidge.Common.Util.log('routeStepChanged idx=%s' % idx)
if idx is None or newStep is None:
	return
draft = self.view.custom.state.editDraft
rawSteps = _g(draft, 'steps') or []
steps = list(rawSteps)
if idx < 0 or idx >= len(steps):
	return
steps[idx] = dict(newStep) if isinstance(newStep, dict) else newStep
newDraft = {'Id': _g(draft, 'Id'), 'Name': _g(draft, 'Name'), 'EffectiveFrom': _g(draft, 'EffectiveFrom'), 'steps': steps}
self.view.custom.state.editDraft = newDraft
self.rootContainer.broadcastDirty(True)

def _g(obj, key):
	try:
		return obj[key]
	except Exception:
		return None
if payload is None:
	return
idx = _g(payload, 'rowIndex')
BlueRidge.Common.Util.log('routeStepMoveUp idx=%s' % idx)
if idx is None or idx <= 0:
	return
draft = self.view.custom.state.editDraft
rawSteps = _g(draft, 'steps') or []
steps = list(rawSteps)
if idx >= len(steps):
	return
steps[idx-1], steps[idx] = steps[idx], steps[idx-1]
newDraft = {'Id': _g(draft, 'Id'), 'Name': _g(draft, 'Name'), 'EffectiveFrom': _g(draft, 'EffectiveFrom'), 'steps': steps}
self.view.custom.state.editDraft = newDraft
self.rootContainer.broadcastDirty(True)

def _g(obj, key):
	try:
		return obj[key]
	except Exception:
		return None
if payload is None:
	return
idx = _g(payload, 'rowIndex')
BlueRidge.Common.Util.log('routeStepMoveDown idx=%s' % idx)
draft = self.view.custom.state.editDraft
rawSteps = _g(draft, 'steps') or []
steps = list(rawSteps)
if idx is None or idx < 0 or idx >= len(steps) - 1:
	return
steps[idx+1], steps[idx] = steps[idx], steps[idx+1]
newDraft = {'Id': _g(draft, 'Id'), 'Name': _g(draft, 'Name'), 'EffectiveFrom': _g(draft, 'EffectiveFrom'), 'steps': steps}
self.view.custom.state.editDraft = newDraft
self.rootContainer.broadcastDirty(True)

def _g(obj, key):
	try:
		return obj[key]
	except Exception:
		return None
if payload is None:
	return
idx = _g(payload, 'rowIndex')
BlueRidge.Common.Util.log('routeStepRemove idx=%s' % idx)
if idx is None:
	return
draft = self.view.custom.state.editDraft
rawSteps = _g(draft, 'steps') or []
steps = list(rawSteps)
if idx < 0 or idx >= len(steps):
	return
del steps[idx]
newDraft = {'Id': _g(draft, 'Id'), 'Name': _g(draft, 'Name'), 'EffectiveFrom': _g(draft, 'EffectiveFrom'), 'steps': steps}
self.view.custom.state.editDraft = newDraft
self.rootContainer.broadcastDirty(True)
